  ('aboriginal-64311456-moex-00279', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '關於行政訴訟重新審理程序之敘述，下列何者錯誤？', '["聲請重新審理不合法者，行政法院應以裁定駁回之", "開始重新審理之裁定確定後，應即回復原訴訟程序，依其審級更為審判", "聲請人於回復原訴訟程序後，當然參加訴訟", "聲請重新審理應停止原確定判決執行之效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00280', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '主管機關依傳染病防治法進入甲之住宅執行病媒蚊防治消毒噴藥，雖合法噴灑藥劑仍造成住宅內電器故 障，甲可如何救濟？', '["應向主管機關請求國家賠償", "應依民法規定向噴藥之人員請求損失補償", "應類推特別犧牲理論，向主管機關請求損失補償", "應向行政法院單獨提起損害賠償之訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00281', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '關於國家賠償之敘述，下列何者錯誤？', '["中華民國人民在甲國，依法得在該國享受國家賠償之同等權利，則甲國之人民乙在中華民國亦得請求國 家賠償", "人民依照國家賠償法之規定主張國家賠償，須先以書面向賠償義務機關請求賠償", "人民對於行政法人亦得主張國家賠償", "公務員違法執行職務縱使無故意過失，國家亦應負損害賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00282', 'aboriginal-64311456', 'aboriginal-64311456-moex-111-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '於開放之山域、水域等自然公物，經管理機關已就使用該公物為適當之警告或標示，而人民仍從事冒險或 具危險性活動者，其損害賠償責任如何釐清？', '["由該公務之管理機關負國家賠償責任", "該公物之管理機關不負國家賠償責任", "該公物之管理機關得主張減輕賠償責任", "該公物之管理機關得主張過失相抵"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "86c821c6be4c", "answer_pdf_sha1": "b3a415d6eb0d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "603", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
